      "\"http://www.w3.org/MarkUp/DTD/xhtml-rdfa-1.dtd\">";

   // Create a working buffer for finding the DOCTYPE
   doctype_buffer = (char*)malloc(*bytes + 2);
   memcpy(doctype_buffer, context->working_buffer, *bytes);
