   doctype_position = strstr(doctype_buffer, "<!DOCTYPE");

   // if a doctype declaration was found, attempt to replace it
   if(doctype_position != NULL)
   {
      char* new_doctype_buffer = NULL;
      size_t new_doctype_buffer_length = 0;
